import { Outlet } from "react-router-dom";
import Sidebar from "@/components/Sidebar";

export default function Layout() {
    return (
        <div className="min-h-screen flex bg-[var(--ttm-bg)] text-[var(--ttm-text)]">
            <Sidebar />
